### File: `/Users/pc035860/code/agent-tail/src/index.ts`

**[Low] Finding 8 -- Agent selection uses nested ternary chain (Lines 86-93)**

```typescript
const agent: Agent =
  options.agentType === 'codex'
    ? new CodexAgent({ verbose: options.verbose })
    : options.agentType === 'gemini'
      ? new GeminiAgent({ verbose: options.verbose })
      : options.agentType === 'cursor'
        ? new CursorAgent({ verbose: options.verbose })
        : new ClaudeAgent({ verbose: options.verbose });
```

This nested ternary grows with each new agent. A `Record<AgentType, () => Agent>` factory map or a simple function would be cleaner and exhaustive-check friendly:

```typescript
function createAgent(type: AgentType, opts: ParserOptions): Agent {
  const agents: Record<AgentType, () => Agent> = {
    codex: () => new CodexAgent(opts),
    claude: () => new ClaudeAgent(opts),
    gemini: () => new GeminiAgent(opts),
    cursor: () => new CursorAgent(opts),
  };
  return agents[type]();
}
```

This also guarantees a compile-time error if a new `AgentType` variant is added without a corresponding factory entry. Low priority since the current code works, but worthwhile given the project is actively adding agents.

